import com.pinterest.ktlint.test.KtLintAssertThat.Companion.assertThatRule
import com.pinterest.ktlint.test.MULTILINE_STRING_QUOTE
import org.junit.jupiter.api.Test

/**
 * Test for raw string false positive with let blocks.
 * Issue: When using `let` blocks inside raw strings with lines longer than max_line_length,
 * the wrapping rule incorrectly reports "Missing newline after {".
 */
internal class WrappingRuleIssueTest {
    private val wrappingRuleAssertThat = assertThatRule { WrappingRule() }

    @Test
    fun `Given a raw string with let block inside and line exceeds max line length, should not report wrapping violation`() {
        val code =
            """
            package test

            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table_name_long_enough_so_max_line_length_is_met_and_wrapping_rule_is_violated_and_generates_an_error
                        WHERE 1 = 1
                        ${'$'}{query.gameId?.let { "AND id = ?" } ?: ""}
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        // This should not produce any lint violations
        wrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 160)
            .hasNoLintViolations()
    }

    @Test
    fun `Given a raw string with let block inside and short lines, should not report wrapping violation`() {
        val code =
            """
            package test

            class QueryGenerator {
                fun getQueryString(query: QueryRequest): String {
                    val q = $MULTILINE_STRING_QUOTE
                        SELECT *
                        FROM table
                        WHERE 1 = 1
                        ${'$'}{query.gameId?.let { "AND id = ?" } ?: ""}
                    $MULTILINE_STRING_QUOTE
                    return q
                }
            }

            data class QueryRequest(
                val gameId: String?,
            )
            """.trimIndent()
        // This should not produce any lint violations
        wrappingRuleAssertThat(code)
            .withEditorConfigOverride(MAX_LINE_LENGTH_PROPERTY to 160)
            .hasNoLintViolations()
    }

    companion object {
        private const val MAX_LINE_LENGTH_PROPERTY = 
            com.pinterest.ktlint.core.api.editorconfig.MAX_LINE_LENGTH_PROPERTY
    }
}
"}

